module RefModule (count, clk, reset, en);
   input clk, reset, en;
   output [3:0] count;

   reg [3:0] count;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
      if (reset)
         count <= 4'b0;
      else if (en)
         count <= count + 1;
   end

endmodule
